#include <bits/stdc++.h>#include<algorithm>#include<utility>using namespace std; // --- FAST I/O & SHORTCUTS ---using ll = long long;using vll = vector<long long>;using vi = vector<int>;using pii = pair<int, int>; // Constantsconst ll MOD = 1e9 + 7;const ll INF = 1e18; // --- LOGIC ---void solve() {    int n;    long long largest = 0,smallest = 0;    cin >> n;        vll a(n);    for(int i=0; i<n; i++){         cin >> a[i];        //smallest = min(smallest, a[i]);        //largest = max(largest, a[i]);            }    sort(a.begin(), a.end());    if(a[0] == a[n-1]){        cout<<"NO\n";        return;    }    else{        cout<<"YES\n";        cout<<a[n-1]<<" "<<a[0]<<" ";        for(int i=1; i<n-1; i++){            cout<<a[i]<<" ";        }        cout<<"\n";     }      } // --- MAIN DRIVER ---int main() {    // Fast I/O: 10x faster input reading    ios_base::sync_with_stdio(false);    cin.tie(NULL);     int T = 1;    cin >> T; // Comment this out if problem has NO test cases    while (T--) {        solve();    }    return 0;}